export function processScenario(scenario: Scenario): ScenarioResult {
  const results = scenario.steps.map((step) => {
    const items = step.items || [];
    const mainItems = items.filter((i) => !COMPONENT_TYPES.has(i.type));
    const components = items.filter((i) => COMPONENT_TYPES.has(i.type));
    const mainPremium = mainItems.reduce((sum, item) => {
      const base = BASE_PREMIUMS[item.type];
      let itemSurcharge = 0;
      if (item.cursed) {
        itemSurcharge += base * 0.5;
      }
      if (item.enchantment >= 5) {
        itemSurcharge += base * 0.3;
      }
      return sum + base + itemSurcharge;
    }, 0);
    const componentPremium = computeComponentPremium(components);
    const premium = mainPremium + componentPremium + PROCESSING_FEE;
    return { premium };
  });
  return { results };
}

