    const mainPremium = mainItems.reduce((sum, item) => {
      const base = BASE_PREMIUMS[item.type];
      let itemSurcharge = 0;
      if (item.cursed) {
        itemSurcharge += base * 0.5;
      }
      if (item.enchantment >= 5) {
        itemSurcharge += base * 0.3;
      }
      return sum + base + itemSurcharge;
    }, 0);
    const componentPremium = computeComponentPremium(components);
    const premium = mainPremium + componentPremium + PROCESSING_FEE;
    return { premium };
  });
